        {"id": "r33", "q": "Сколько букв и звуков в слове 'Ёж'?", "o": ["2б, 3зв", "2б, 2зв", "3б, 3зв", "3б, 4зв"], "a": 0, "e": "Ёж: [й'], [о], [ш] - 2 буквы, 3 звука.", "t": "Фонетика", "d": 1},
