        {"id": "r35", "q": "Какое прилагательное качественное?", "o": ["деревянный", "лисий", "красивый", "городской"], "a": 2, "e": "Красивый - качественное (может быть красивее, очень красивый).", "t": "Морфология", "d": 2},
