        {"id": "r53", "q": "В предложении: 'Мне грустно.' - какое оно по составу?", "o": ["Двусоставное", "Односоставное безличное", "Назывное", "Сложное"], "a": 1, "e": "", "t": "Синтаксис", "d": 1},
